CREATE TABLE `audit_sync_job` (`id` INT(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'Manual synchronization', `scope` ENUM('both','organizations','users') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'both', `status` ENUM('FAILED','PENDING','SUCCESS') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending', `message` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci) ENGINE = innodb CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci
ALTER TABLE `priv_sync_att_linkset` CHANGE `attribute_qualifier` `attribute_qualifier` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '\''
